"""Status checks for stow and force-copy packages."""
from __future__ import annotations

import asyncio
import subprocess as _sp
from pathlib import Path
from typing import Dict, List, Tuple

from . import config
from .types import PkgType
from .discover import list_syncable_files, build_win_path


def _is_symlink(path: Path) -> bool:
    """Like path.is_symlink() but falls back to sudo test -L
    for paths the user cannot stat (e.g. /root/...)."""
    try:
        if path.is_symlink():
            return True
    except PermissionError:
        pass
    try:
        return _sp.run(["sudo", "test", "-L", str(path)], capture_output=True).returncode == 0
    except Exception:
        return False


# ── stow status (Linux types) ─────────────────────────────────

def check_stow_status(pkg: Path, pt: PkgType) -> Tuple[int, int]:
    """
    Return (stowed_count, total_stowable).
    Uses pt.sync_target to find the stow destination.
    """
    target = pt.sync_target
    if not pt.uses_stow or target is None or not pkg.is_dir():
        return (0, 0)

    stowed = 0
    total = 0

    for f in pkg.rglob("*"):
        if not f.is_file() or ".git" in f.parts:
            continue
        total += 1
        rel = f.relative_to(pkg)
        dest = target / rel

        linked = _is_symlink(dest)
        if linked:
            linked = dest.exists() or _is_symlink(dest)
        if not linked:
            p = dest.parent
            while p != target and p != p.parent:
                if _is_symlink(p) and (p.exists() or _is_symlink(p)):
                    linked = True
                    break
                p = p.parent
        if linked:
            stowed += 1

    return (stowed, total)


# ── force-copy status (Windows types — WSL→Win only) ─────────

def check_copy_status(pkg: Path, pt: PkgType) -> Dict[str, int]:
    """
    Check force-copy status for all syncable files in *pkg*.

    Dotfiles repo is source of truth — only WSL→Win direction.

    Returns:
      synced           — both sides exist and are identical
      outdated_local   — WSL side is newer (needs sync)
      missing_remote   — exists in WSL only
      skipped          — excluded or too large
      error            — stat failed
    """
    counts = {
        "synced": 0, "outdated_local": 0,
        "missing_remote": 0, "skipped": 0, "error": 0,
    }

    if not pkg.is_dir():
        return counts

    files = list_syncable_files(pkg)
    for f in files:
        try:
            if config.MAX_SYNC_SIZE_BYTES > 0 and f.stat().st_size > config.MAX_SYNC_SIZE_BYTES:
                counts["skipped"] += 1
                continue
        except OSError:
            counts["error"] += 1
            continue

        win_path = build_win_path(f, pkg, pt)

        try:
            win_exists = win_path.exists() or win_path.is_symlink()
        except OSError:
            win_exists = True

        if not win_exists:
            counts["missing_remote"] += 1
            continue

        try:
            ws = f.stat()
            wn = win_path.stat()
        except OSError:
            counts["error"] += 1
            continue

        if abs(ws.st_mtime - wn.st_mtime) < 1.0 and ws.st_size == wn.st_size:
            counts["synced"] += 1
        elif ws.st_mtime > wn.st_mtime:
            counts["outdated_local"] += 1
        # else: Windows is newer — ignored (dotfiles always wins)

    return counts


# ── async wrappers ────────────────────────────────────────────

async def check_stow_status_async(pkg: Path, pt: PkgType) -> Tuple[int, int]:
    return await asyncio.to_thread(check_stow_status, pkg, pt)

async def check_copy_status_async(pkg: Path, pt: PkgType) -> Dict[str, int]:
    return await asyncio.to_thread(check_copy_status, pkg, pt)


def status_text(counts: Dict[str, int]) -> str:
    """Human-readable one-line summary of sync status (WSL→Win only)."""
    parts = []
    if counts.get("synced"):
        parts.append(f"{counts['synced']} synced")
    if counts.get("outdated_local"):
        parts.append(f"{counts['outdated_local']} needs-sync")
    if counts.get("missing_remote"):
        parts.append(f"{counts['missing_remote']} missing-win")
    if counts.get("skipped"):
        parts.append(f"{counts['skipped']} skipped")
    if not parts:
        return "empty"
    return ", ".join(parts)

"""Package type enumeration and helpers."""
from __future__ import annotations

from enum import Enum
from pathlib import Path
from typing import Optional

from . import config


class PkgType(Enum):
    """Dotfile package type — suffix determines target directory."""

    # ── Linux ──────────────────────────────────────────────────
    USER   = "user"       # ~/
    CONFIG = "config"     # ~/.config/
    LOCAL  = "local"      # ~/.local/
    ROOT   = "root"       # / (sudo)
    META   = "meta"       # manual only

    # ── Windows ────────────────────────────────────────────────
    WINUSER    = "winuser"     # C:\Users\{name}\
    WINCONFIG  = "winconfig"   # C:\Users\{name}\.config\
    WINLOCAL   = "winlocal"    # C:\Users\{name}\AppData\Local\
    WINROAMING = "winroaming"  # C:\Users\{name}\AppData\Roaming\

    # ── properties ──────────────────────────────────────────────

    @property
    def suffix(self) -> str:
        return f".{self.value}"

    @property
    def sync_target(self) -> Optional[Path]:
        """Target directory for this type (stow or force-copy)."""
        return {
            PkgType.USER:       config.USER_TARGET,
            PkgType.CONFIG:     config.CONFIG_TARGET,
            PkgType.LOCAL:      config.LOCAL_TARGET,
            PkgType.ROOT:       config.ROOT_TARGET,
            PkgType.WINUSER:    config.WINUSER_TARGET,
            PkgType.WINCONFIG:  config.WINCONFIG_TARGET,
            PkgType.WINLOCAL:   config.WINLOCAL_TARGET,
            PkgType.WINROAMING: config.WINROAMING_TARGET,
        }.get(self)

    @property
    def needs_sudo(self) -> bool:
        return self == PkgType.ROOT

    @property
    def uses_stow(self) -> bool:
        """Linux types managed by GNU Stow."""
        return self in (PkgType.USER, PkgType.CONFIG, PkgType.LOCAL, PkgType.ROOT)

    @property
    def uses_copy_sync(self) -> bool:
        """Windows types managed by force-copy (WSL → Windows)."""
        return self in (
            PkgType.WINUSER, PkgType.WINCONFIG,
            PkgType.WINLOCAL, PkgType.WINROAMING,
        )

    @property
    def is_linux(self) -> bool:
        return self in (PkgType.USER, PkgType.CONFIG, PkgType.LOCAL, PkgType.ROOT, PkgType.META)

    @property
    def is_windows(self) -> bool:
        return self in (
            PkgType.WINUSER, PkgType.WINCONFIG,
            PkgType.WINLOCAL, PkgType.WINROAMING,
        )

    @property
    def is_linux_config(self) -> bool:
        """True for types that target $HOME sub-paths (not /)."""
        return self in (PkgType.USER, PkgType.CONFIG, PkgType.LOCAL)


# ── helpers ───────────────────────────────────────────────────

def suffix_to_type(suffix: str) -> Optional[PkgType]:
    """Map a directory suffix ('.config') to PkgType."""
    for pt in PkgType:
        if pt.suffix == suffix and suffix:
            return pt
    return None

def type_from_dir_name(name: str) -> Optional[PkgType]:
    """Infer PkgType from a directory name, or None."""
    for pt in PkgType:
        s = pt.suffix
        if s and name.endswith(s) and len(name) > len(s):
            return pt
    return None

# ── human-readable labels ─────────────────────────────────────

_TYPE_LABELS: dict[PkgType, str] = {
    PkgType.USER:       "~",
    PkgType.CONFIG:     "~/.config",
    PkgType.LOCAL:      "~/.local",
    PkgType.ROOT:       "/",
    PkgType.META:       "manual",
    PkgType.WINUSER:    f"C:\\Users\\{config.WIN_USERNAME}",
    PkgType.WINCONFIG:  f"C:\\Users\\{config.WIN_USERNAME}\\.config",
    PkgType.WINLOCAL:   f"C:\\Users\\{config.WIN_USERNAME}\\AppData\\Local",
    PkgType.WINROAMING: f"C:\\Users\\{config.WIN_USERNAME}\\AppData\\Roaming",
}

def type_label(pt: PkgType) -> str:
    """Human-readable target for a package type."""
    return _TYPE_LABELS.get(pt, pt.value)

"""Utility functions: shell, filesystem, environment checks."""
from __future__ import annotations

import asyncio
import fnmatch
import os
import shutil
import subprocess
from pathlib import Path
from typing import List, Optional

from . import config


# ── environment checks ─────────────────────────────────────────

def is_wsl() -> bool:
    """True when running under WSL."""
    return Path("/proc/sys/fs/binfmt_misc/WSLInterop").exists()

def has_pwsh() -> bool:
    return shutil.which("pwsh.exe") is not None

def has_stow() -> bool:
    return shutil.which("stow") is not None


# ── filesystem metrics (os.scandir for speed) ──────────────────

def count_files(directory: Path) -> int:
    """Count regular files recursively, skipping excluded patterns.
    Uses os.scandir for fast traversal."""
    if not directory.is_dir():
        return 0
    n = 0
    for dirpath, dirnames, filenames in os.walk(directory):
        dirnames[:] = [d for d in dirnames if not _quick_exclude_dir(d)]
        dp = Path(dirpath)
        for fn in filenames:
            if not _is_excluded(dp / fn):
                n += 1
    return n

def dir_size(directory: Path) -> int:
    """Total byte size of all regular files, skipping excluded patterns.
    Uses os.scandir for fast traversal."""
    if not directory.is_dir():
        return 0
    total = 0
    for dirpath, dirnames, filenames in os.walk(directory):
        dirnames[:] = [d for d in dirnames if not _quick_exclude_dir(d)]
        dp = Path(dirpath)
        for fn in filenames:
            fp = dp / fn
            if not _is_excluded(fp):
                try:
                    total += os.stat(fp).st_size
                except OSError:
                    pass
    return total

def fmt_size(n_bytes: int) -> str:
    """Human-readable byte size."""
    if n_bytes < 1024:
        return f"{n_bytes} B"
    elif n_bytes < 1024 * 1024:
        return f"{n_bytes / 1024:.1f} KB"
    elif n_bytes < 1024 * 1024 * 1024:
        return f"{n_bytes / (1024 * 1024):.1f} MB"
    else:
        return f"{n_bytes / (1024 * 1024 * 1024):.2f} GB"


# ── exclusion ──────────────────────────────────────────────────

def _quick_exclude_dir(dirname: str) -> bool:
    """Fast exclusion for directory names (no fnmatch)."""
    return dirname in {".git", "__pycache__", "node_modules", ".mypy_cache",
                       ".ruff_cache", ".pixi"}

def _is_excluded(path: Path) -> bool:
    """Check whether *path* matches any EXCLUDE_PATTERNS."""
    for part in path.parts:
        for pat in config.EXCLUDE_PATTERNS:
            if fnmatch.fnmatch(part, pat):
                return True
    return False

def is_excluded(path: Path) -> bool:
    """Public alias."""
    return _is_excluded(path)


# ── async wrappers ────────────────────────────────────────────

async def count_files_async(directory: Path) -> int:
    return await asyncio.to_thread(count_files, directory)

async def dir_size_async(directory: Path) -> int:
    return await asyncio.to_thread(dir_size, directory)


# ── subprocess ─────────────────────────────────────────────────

def run(
    cmd: List[str],
    *,
    sudo: bool = False,
    cwd: Optional[Path] = None,
    dry_run: bool = False,
    check: bool = True,
) -> subprocess.CompletedProcess:
    """Run a command, optionally with sudo."""
    from .display import dim, error, info as _info

    if sudo:
        cmd = ["sudo"] + cmd
    cmd_str = " ".join(cmd)

    if dry_run:
        dim(f"  DRY-RUN  {cmd_str}")
        return subprocess.CompletedProcess(cmd, 0, "", "")

    try:
        r = subprocess.run(cmd, cwd=cwd, capture_output=True, text=True, check=check)
        if r.stdout.strip():
            dim(f"       {r.stdout.strip()}")
        if r.stderr.strip():
            dim(f"       {r.stderr.strip()}")
        return r
    except subprocess.CalledProcessError as e:
        error(f"Command failed (rc={e.returncode}): {cmd_str}")
        if e.stdout:
            _info(e.stdout)
        if e.stderr:
            error(e.stderr)
        raise
